function candidate(input, settings) {
  if (typeof input !== "string") {
    throw new TypeError("argument must be a string");
  }

  var result = {};
  var options = settings || {};
  var decodeValue = typeof options.decode === "function" ? options.decode : decodeURIComponent;
  var pieces = input.split(/; */);

  for (var index = 0; index < pieces.length; index += 1) {
    var part = pieces[index];
    var equalsAt = part.indexOf("=");

    if (equalsAt === -1) {
      continue;
    }

    var name = part.slice(0, equalsAt).trim();

    if (Object.prototype.hasOwnProperty.call(result, name)) {
      continue;
    }

    var encoded = part.slice(equalsAt + 1).trim();

    if (encoded.length >= 2 && encoded[0] === '"' && encoded[encoded.length - 1] === '"') {
      encoded = encoded.slice(1, -1);
    }

    try {
      result[name] = decodeValue(encoded);
    } catch (error) {
      result[name] = encoded;
    }
  }

  return result;
}
